def _json_request_deserializer(data: bytes) -> Dict[str, Any]:
    if not data:
        return {}
    try:
        return json.loads(data.decode("utf-8"))
    except Exception as e:
        raise ServiceError(
            "Invalid JSON request payload",
            code=grpc.StatusCode.INVALID_ARGUMENT,
            internal_state={"raw_len": len(data), "decode_error": str(e)},
        )


def _json_response_serializer(obj: Any) -> bytes:
    return _safe_json_dumps(obj).encode("utf-8")


class ExampleTroubleshootingService(grpc.GenericRpcHandler):
    SERVICE = "example.Troubleshooting"
    METHODS = {
        "Echo": "unary_unary",
        "Crash": "unary_unary",
        "Divide": "unary_unary",
    }

    def service(self, handler_call_details):
        method_full = handler_call_details.method or ""
        parts = method_full.split("/")
        if len(parts) != 3 or not parts[1] or not parts[2]:
            return None
        service_name = parts[1]
        method_name = parts[2]
        if service_name != self.SERVICE:
            return None
        if method_name not in self.METHODS:
            return None

        if method_name == "Echo":
            return grpc.unary_unary_rpc_method_handler(
                self.Echo,
                request_deserializer=_json_request_deserializer,
                response_serializer=_json_response_serializer,
            )
        if method_name == "Crash":
            return grpc.unary_unary_rpc_method_handler(
                self.Crash,
                request_deserializer=_json_request_deserializer,
                response_serializer=_json_response_serializer,
            )
        if method_name == "Divide":
            return grpc.unary_unary_rpc_method_handler(
                self.Divide,
                request_deserializer=_json_request_deserializer,
                response_serializer=_json_response_serializer,
            )
        return None

    def Echo(self, request: Dict[str, Any], context: grpc.ServicerContext) -> Dict[str, Any]:
        if not isinstance(request, dict):
            raise ServiceError(
                "Request must be a JSON object",
                code=grpc.StatusCode.INVALID_ARGUMENT,
                internal_state={"type": str(type(request))},
            )
        return {"ok": True, "echo": request}

    def Divide(self, request: Dict[str, Any], context: grpc.ServicerContext) -> Dict[str, Any]:
        a = request.get("a")
        b = request.get("b")
        if not isinstance(a, (int, float)) or not isinstance(b, (int, float)):
            raise ServiceError(
                "Fields 'a' and 'b' must be numbers",
                code=grpc.StatusCode.INVALID_ARGUMENT,
                internal_state={"a": a, "b": b, "a_type": str(type(a)), "b_type": str(type(b))},
            )
        if b == 0:
            raise ServiceError(
                "Division by zero",
                code=grpc.StatusCode.FAILED_PRECONDITION,
                internal_state={"a": a, "b": b},
            )
        return {"ok": True, "result": a / b}

    def Crash(self, request: Dict[str, Any], context: grpc.ServicerContext) -> Dict[str, Any]:
        internal_state = {
            "request_keys": list(request.keys()) if isinstance(request, dict) else None,
            "env_subset": {k: os.getenv(k) for k in ("SERVICE_NAME", "DEBUG_GRPC_ERRORS")},
        }
        # Deliberate crash with internal state included
        raise ServiceError(
            "Deliberate crash for testing",
            code=grpc.StatusCode.INTERNAL,
            internal_state=internal_state,
        )


def serve(
    host: str = "0.0.0.0",
    port: int = 50051,
    max_workers: int = 20,
) -> grpc.Server:
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        interceptors=(ErrorHandlingInterceptor(),),
        options=[
            ("grpc.max_send_message_length", 10 * 1024 * 1024),
            ("grpc.max_receive_message_length", 10 * 1024 * 1024),
        ],
    )
    server.add_generic_rpc_handlers((ExampleTroubleshootingService(),))
    server.add_insecure_port(f"{host}:{port}")
    server.start()
    _log(
        _safe_json_dumps(
            {
                "event": "grpc_server_started",
                "service": SERVICE_NAME,
                "listen": f"{host}:{port}",
                "debug_grpc_errors": DEBUG_GRPC_ERRORS,
                "max_error_details_bytes": MAX_DETAILS_BYTES,
            }
        )
    )
    return server


def main():
    host = os.getenv("GRPC_HOST", "0.0.0.0")
    port = int(os.getenv("GRPC_PORT", "50051"))
    max_workers = int(os.getenv("GRPC_MAX_WORKERS", "20"))
    server = serve(host=host, port=port, max_workers=max_workers)
    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        pass


if __name__ == "__main__":
    main()